object PaymentValidator {
    fun validateAmount(amount: BigDecimal) {
        if (amount <= BigDecimal.ZERO) {
            throw PaymentValidationException("Amount must be greater than zero")
        }
        if (amount.scale() > 2) {
            throw PaymentValidationException("Amount cannot exceed 2 decimal places")
        }
    }

    fun validateCurrency(currency: String) {
        if (!currency.matches(Regex("^[A-Z]{3}$"))) {
            throw PaymentValidationException("Currency must be a 3-letter ISO code")
        }
    }

    fun validatePan(pan: String) {
        val sanitized = pan.filter(Char::isDigit)
        if (sanitized.length !in 12..19 || !passesLuhn(sanitized)) {
            throw PaymentValidationException("Invalid payment card number")
        }
    }

    fun validateCvv(cvv: String) {
        if (!cvv.matches(Regex("^\\d{3,4}$"))) {
            throw PaymentValidationException("Invalid CVV")
        }
    }

    fun validateProductId(productId: String) {
        if (productId.isBlank()) throw PaymentValidationException("Product ID cannot be blank")
    }

    fun validatePurchaseToken(token: String) {
        if (token.length < 16) throw PaymentValidationException("Purchase token too short")
    }

    private fun passesLuhn(number: String): Boolean {
        var sum = 0
        var alternate = false
        for (i in number.length - 1 downTo 0) {
            var n = number[i].digitToInt()
            if (alternate) {
                n *= 2
                if (n > 9) n -= 9
            }
            sum += n
            alternate = !alternate
        }
        return sum % 10 == 0
    }
}

class PaymentTokenizationService(
    private val cryptoEngine: SecureCryptoEngine = SecureCryptoEngine()
) {
    @Throws(PaymentValidationException::class, PaymentSecurityException::class)
    fun tokenizeCard(pan: String, cvv: String): PaymentToken {
        PaymentValidator.validatePan(pan)
        PaymentValidator.validateCvv(cvv)

        val sanitizedPan = pan.filter(Char::isDigit)
        val encryptedPan = cryptoEngine.encrypt(sanitizedPan)
        val encryptedCvv = cryptoEngine.encrypt(cvv)

        return PaymentToken(
            tokenId = UUID.randomUUID().toString(),
            encryptedPan = encryptedPan.cipherText,
            encryptedCvv = encryptedCvv.cipherText,
            panIv = encryptedPan.iv,
            cvvIv = encryptedCvv.iv,
            last4 = sanitizedPan.takeLast(4)
        )
    }

    @Throws(PaymentSecurityException::class)
    fun revealPan(token: PaymentToken): String {
        return cryptoEngine.decrypt(
            EncryptedPayload(
                cipherText = token.encryptedPan,
                iv = token.panIv
            )
        )
    }
}

class PaymentProcessor(
    private val context: Context,
    private val gateway: PaymentGateway,
