        if (recipientId.isBlank()) throw PaymentValidationException("Recipient ID cannot be blank")

        val transaction = WalletTransaction(
            transactionId = UUID.randomUUID().toString(),
            walletId = walletId,
            amount = amount,
            currency = currency,
            recipientId = recipientId,
            nonce = UUID.randomUUID().toString()
        )
        return gateway.processWalletTransaction(transaction)
    }

