        if (orderId.isBlank()) throw PaymentValidationException("Order ID cannot be blank")
        if (userId.isBlank()) throw PaymentValidationException("User ID cannot be blank")

        return gateway.verifyInAppPurchase(
            InAppPurchaseRequest(
                productId = productId,
                orderId = orderId,
                userId = userId,
                purchaseToken = purchaseToken
            )
        )
    }
}

